import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

public class RecentInvoiceAdapter extends RecyclerView.Adapter<RecentInvoiceAdapter.InvoiceViewHolder> {

    private final List<RecentInvoiceUiModel> items = new ArrayList<>();

    @NonNull
    @Override
    public InvoiceViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext()).inflate(R.layout.item_invoice, parent, false);
        return new InvoiceViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull InvoiceViewHolder holder, int position) {
        holder.bind(items.get(position));
    }

    @Override
    public int getItemCount() {
        return items.size();
    }

    public void submitList(List<RecentInvoiceUiModel> data) {
        items.clear();
        if (data != null) {
            items.addAll(data);
        }
        notifyDataSetChanged();
    }

    static class InvoiceViewHolder extends RecyclerView.ViewHolder {
        private final TextView tvCustomer;
        private final TextView tvInvoiceId;
        private final TextView tvAmount;
        private final TextView tvStatus;

        InvoiceViewHolder(@NonNull View itemView) {
            super(itemView);
            tvCustomer = itemView.findViewById(R.id.tvProductId);
            tvInvoiceId = itemView.findViewById(R.id.tvQuantity);
            tvAmount = itemView.findViewById(R.id.tvTotalPrice);
            tvStatus = itemView.findViewById(R.id.tvUnitPrice);
        }

        void bind(RecentInvoiceUiModel item) {
            tvCustomer.setText(item.customerName);
            tvInvoiceId.setText(item.invoiceId);
            tvAmount.setText(item.totalAmount);
            tvStatus.setText(item.paymentStatus);

            String status = item.paymentStatus.toLowerCase(Locale.US);
            if ("paid".equals(status)) {
                tvStatus.setBackgroundResource(R.drawable.bg_status_paid);
                tvStatus.setTextColor(ContextCompat.getColor(itemView.getContext(), R.color.badge_paid_text));
            } else if ("credit".equals(status)) {
                tvStatus.setBackgroundResource(R.drawable.bg_status_credit);
                tvStatus.setTextColor(ContextCompat.getColor(itemView.getContext(), R.color.badge_credit_text));
            } else {
                tvStatus.setBackgroundResource(R.drawable.bg_status_cheque);
                tvStatus.setTextColor(ContextCompat.getColor(itemView.getContext(), R.color.badge_cheque_text));
            }
        }
    }
}

package com.hfad.agencyapp.ui.auth;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

import com.hfad.agencyapp.databinding.ActivityLoginBinding;
import com.hfad.agencyapp.ui.dashboard.DashboardActivity;
import com.hfad.agencyapp.utils.ValidationUtils;
import com.hfad.agencyapp.viewmodel.AuthViewModel;

public class LoginActivity extends AppCompatActivity {

    private ActivityLoginBinding binding;
    private AuthViewModel viewModel;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityLoginBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        viewModel = new ViewModelProvider(this).get(AuthViewModel.class);

        // Check if already logged in
        if (viewModel.getCurrentUser() != null) {
            startActivity(new Intent(this, DashboardActivity.class));
            finish();
            return;
        }

        binding.btnLogin.setOnClickListener(v -> handleLogin());
        binding.btnSignUp.setOnClickListener(v -> handleSignUp());

        // FOR TESTING: Add demo/skip button
        binding.btnSignUp.setText("Demo (Skip Auth)");
        binding.btnSignUp.setOnClickListener(v -> {
            // Skip Firebase auth and go directly to dashboard for testing
            Toast.makeText(this, "Entering demo mode...", Toast.LENGTH_SHORT).show();
            startActivity(new Intent(this, DashboardActivity.class));
            finish();
        });

        viewModel.userLive.observe(this, user -> {
            binding.progress.setVisibility(View.GONE);
            if (user != null) {
                startActivity(new Intent(this, DashboardActivity.class));
                finish();
            }
        });

        viewModel.errorMessage.observe(this, error -> {
            binding.progress.setVisibility(View.GONE);
            if (error != null && !error.isEmpty()) {
                Toast.makeText(this, error, Toast.LENGTH_LONG).show();
            }
        });

        viewModel.loading.observe(this, isLoading -> {
            binding.progress.setVisibility(isLoading ? View.VISIBLE : View.GONE);
            binding.btnLogin.setEnabled(!isLoading);
            binding.btnSignUp.setEnabled(!isLoading);
        });
    }

    private void handleLogin() {
        String email = binding.etEmail.getText().toString().trim();
        String password = binding.etPassword.getText().toString();

        // DEMO MODE: Skip validation and go to dashboard
        if (email.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Demo Mode: Entering Dashboard...", Toast.LENGTH_SHORT).show();
            startActivity(new Intent(this, DashboardActivity.class));
            finish();
            return;
        }

        // Optional: Try real authentication if email/password provided
        if (!ValidationUtils.isValidEmail(email)) {
            binding.etEmail.setError("Invalid email format");
            return;
        }
        if (!ValidationUtils.isValidPassword(password)) {
            binding.etPassword.setError("Password must be at least 6 characters");
            return;
        }

        // Try Firebase authentication
        viewModel.signIn(email, password);
    }

    private void handleSignUp() {
        String email = binding.etEmail.getText().toString().trim();
        String password = binding.etPassword.getText().toString();

        if (TextUtils.isEmpty(email)) {
            binding.etEmail.setError("Email required");
            return;
        }
        if (!ValidationUtils.isValidEmail(email)) {
            binding.etEmail.setError("Invalid email format");
            return;
        }
        if (TextUtils.isEmpty(password)) {
            binding.etPassword.setError("Password required");
            return;
        }
        if (!ValidationUtils.isValidPassword(password)) {
            binding.etPassword.setError("Password must be at least 6 characters");
            return;
        }

        viewModel.signUp(email, password);
    }
}

package com.hfad.agencyapp.ui.dashboard;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.ContextCompat;
import androidx.recyclerview.widget.LinearLayoutManager;

import com.hfad.agencyapp.databinding.ActivityDashboardBinding;
import com.hfad.agencyapp.R;
import com.hfad.agencyapp.ui.adapters.RecentInvoiceAdapter;
import com.hfad.agencyapp.ui.auth.LoginActivity;
import com.hfad.agencyapp.ui.models.RecentInvoiceUiModel;

import java.util.ArrayList;
import java.util.List;

public class DashboardActivity extends AppCompatActivity {

    private ActivityDashboardBinding binding;
    private RecentInvoiceAdapter invoiceAdapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityDashboardBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());
        getWindow().setStatusBarColor(ContextCompat.getColor(this, R.color.navy_900));

        setupRecyclerView();
        setupQuickActions();
        setupBottomNavigation();
    }

    private void setupRecyclerView() {
        binding.recyclerRecentInvoices.setLayoutManager(new LinearLayoutManager(this));
        invoiceAdapter = new RecentInvoiceAdapter();
        binding.recyclerRecentInvoices.setAdapter(invoiceAdapter);

        List<RecentInvoiceUiModel> sample = new ArrayList<>();
        sample.add(new RecentInvoiceUiModel("ABC Bakers", "INV-2026-001", "Rs. 12,400", "Paid"));
        sample.add(new RecentInvoiceUiModel("Sugar House", "INV-2026-002", "Rs. 8,950", "Credit"));
        sample.add(new RecentInvoiceUiModel("Sweet Oven", "INV-2026-003", "Rs. 5,600", "Cheque"));
        sample.add(new RecentInvoiceUiModel("Royal Cakes", "INV-2026-004", "Rs. 16,220", "Paid"));

        invoiceAdapter.submitList(sample);
    }

    private void setupQuickActions() {
        binding.actionNewInvoice.setOnClickListener(v -> showFeatureToast("New Invoice"));
        binding.actionCustomers.setOnClickListener(v -> showFeatureToast("Customers"));
        binding.actionProducts.setOnClickListener(v -> showFeatureToast("Products"));
        binding.actionSync.setOnClickListener(v -> showFeatureToast("Sync"));

        binding.tvViewAll.setOnClickListener(v -> showFeatureToast("View All Invoices"));
    }

    private void setupBottomNavigation() {
        binding.includeBottomNav.bottomNav.setSelectedItemId(R.id.nav_home);
        binding.includeBottomNav.bottomNav.setOnItemSelectedListener(item -> {
            int id = item.getItemId();
            if (id == R.id.nav_home) {
                return true;
            }
            if (id == R.id.nav_invoices) {
                showFeatureToast("Invoices");
                return true;
            }
            if (id == R.id.nav_customers) {
                showFeatureToast("Customers");
                return true;
            }
            if (id == R.id.nav_more) {
                startActivity(new Intent(this, LoginActivity.class));
                finish();
                return true;
            }
            return false;
        });
    }

    private void showFeatureToast(String feature) {
        Toast.makeText(this, feature + " coming soon", Toast.LENGTH_SHORT).show();
    }
}

