package com.hfad.agencyapp.utils;

import android.graphics.Bitmap;
import android.graphics.BitmapFactory;

import java.io.ByteArrayOutputStream;

public class ImageUtils {

    public static byte[] compressJpeg(byte[] inputBytes, int maxWidth, int quality) {
        if (inputBytes == null || inputBytes.length == 0) return inputBytes;

        BitmapFactory.Options options = new BitmapFactory.Options();
        Bitmap bmp = BitmapFactory.decodeByteArray(inputBytes, 0, inputBytes.length, options);
        if (bmp == null) return inputBytes;

        float scale = Math.min(1f, (float) maxWidth / bmp.getWidth());
        int w = Math.max(1, (int) (bmp.getWidth() * scale));
        int h = Math.max(1, (int) (bmp.getHeight() * scale));

        Bitmap scaled = Bitmap.createScaledBitmap(bmp, w, h, true);
        ByteArrayOutputStream os = new ByteArrayOutputStream();
        scaled.compress(Bitmap.CompressFormat.JPEG, quality, os);

        bmp.recycle();
        scaled.recycle();

        return os.toByteArray();
    }

    public static byte[] compressJpeg(Bitmap bitmap, int quality) {
        ByteArrayOutputStream os = new ByteArrayOutputStream();
        bitmap.compress(Bitmap.CompressFormat.JPEG, quality, os);
        return os.toByteArray();
    }
}

package com.hfad.agencyapp.utils;

import com.hfad.agencyapp.data.entities.Customer;
import com.hfad.agencyapp.data.entities.Invoice;
import com.hfad.agencyapp.data.entities.InvoiceItem;
import com.hfad.agencyapp.data.entities.Product;

import java.text.DateFormat;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.List;
import java.util.Locale;

public class InvoiceGenerator {

    private static final DateFormat dateFormat = new SimpleDateFormat("dd/MM/yyyy HH:mm", Locale.getDefault());

    public static String generateInvoiceText(Invoice invoice, Customer customer, List<InvoiceItem> items, List<Product> products) {
        StringBuilder sb = new StringBuilder();

        // Header
        sb.append("========================================\n");
        sb.append("        CAKE INGREDIENTS SALES\n");
        sb.append("        Invoice Receipt\n");
        sb.append("========================================\n\n");

        // Invoice Details
        sb.append("Invoice #: ").append(invoice.invoiceNumber).append("\n");
        sb.append("Date: ").append(dateFormat.format(new Date(invoice.createdAt))).append("\n\n");

        // Customer Details
        sb.append("Customer:\n");
        if (customer != null) {
            sb.append(customer.name).append("\n");
            sb.append("Phone: ").append(customer.phone).append("\n");
            sb.append("Address: ").append(customer.address).append("\n");
        }
        sb.append("\n");

        // Items
        sb.append("----------------------------------------\n");
        sb.append("Item Details:\n");
        sb.append("----------------------------------------\n");

        for (InvoiceItem item : items) {
            Product product = findProductById(products, item.productId);
            String productName = product != null ? product.name : "Unknown";
            sb.append(String.format("%s\n", productName));
            sb.append(String.format("Qty: %d x %.2f = %.2f\n", item.quantity, item.unitPrice, item.totalPrice));
        }

        sb.append("----------------------------------------\n");
        sb.append(String.format("Subtotal: %.2f\n", invoice.totalAmount));
        sb.append(String.format("Paid: %.2f\n", invoice.paidAmount));
        sb.append(String.format("Outstanding: %.2f\n", invoice.totalAmount - invoice.paidAmount));
        sb.append("\n");

        if (!TextUtils.isEmpty(invoice.note)) {
            sb.append("Note: ").append(invoice.note).append("\n");
        }

        sb.append("========================================\n");
        sb.append("Thank you for your business!\n");
        sb.append("========================================\n");

        return sb.toString();
    }

    public static String generateReceiptForPrinting(Invoice invoice, Customer customer, List<InvoiceItem> items, List<Product> products) {
        StringBuilder sb = new StringBuilder();

        sb.append("  ===== CAKE INGREDIENTS SALES =====\n");
        sb.append("       INVOICE RECEIPT\n");
        sb.append("\n");

        sb.append("Invoice: ").append(invoice.invoiceNumber).append("\n");
        sb.append("Date: ").append(dateFormat.format(new Date(invoice.createdAt))).append("\n");
        sb.append("Customer: ").append(customer != null ? customer.name : "Walk-in").append("\n");
        sb.append("\n");

        sb.append("Items:\n");
        for (InvoiceItem item : items) {
            Product product = findProductById(products, item.productId);
            String productName = product != null ? product.name : "Unknown";
            sb.append(String.format("%-20s %d x %.2f\n", productName, item.quantity, item.unitPrice));
            sb.append(String.format("                        Total: %.2f\n", item.totalPrice));
        }

        sb.append("\n");
        sb.append(String.format("Total Amount: %.2f\n", invoice.totalAmount));
        sb.append(String.format("Paid Amount: %.2f\n", invoice.paidAmount));
        sb.append(String.format("Balance: %.2f\n", invoice.totalAmount - invoice.paidAmount));

        sb.append("\n");
        sb.append("Thank You!\n");

        return sb.toString();
    }

    private static Product findProductById(List<Product> products, long productId) {
        for (Product p : products) {
            if (p.id == productId) return p;
        }
        return null;
    }

    // TextUtils import helper (avoiding Android Text utils dependency in this standalone util)
    public static class TextUtils {
        public static boolean isEmpty(CharSequence str) {
            return str == null || str.length() == 0;
        }
    }
}

package com.hfad.agencyapp.utils;

import android.content.Context;
import android.net.ConnectivityManager;
import android.net.Network;
import android.net.NetworkCapabilities;

public class NetworkUtils {

    public static boolean isOnline(Context context) {
        if (context == null) return false;
        ConnectivityManager cm = (ConnectivityManager) context.getSystemService(Context.CONNECTIVITY_SERVICE);
        if (cm == null) return false;
        Network n = cm.getActiveNetwork();
        if (n == null) return false;
        NetworkCapabilities caps = cm.getNetworkCapabilities(n);
        return caps != null && (caps.hasTransport(NetworkCapabilities.TRANSPORT_WIFI) ||
                caps.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR));
    }
}

package com.hfad.agencyapp.utils;

import android.Manifest;
import android.content.Context;
import android.os.Build;

import androidx.core.content.ContextCompat;

public class PermissionUtils {

    public static String[] getBluetoothPermissions() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            // Android 12+: fine-grained Bluetooth permissions
            return new String[]{
                    Manifest.permission.BLUETOOTH,
                    Manifest.permission.BLUETOOTH_ADMIN,
                    Manifest.permission.BLUETOOTH_CONNECT,
                    Manifest.permission.BLUETOOTH_SCAN
            };
        } else {
            // Android < 12
            return new String[]{
                    Manifest.permission.BLUETOOTH,
                    Manifest.permission.BLUETOOTH_ADMIN
            };
        }
    }

    public static String[] getNetworkPermissions() {
        return new String[]{
                Manifest.permission.INTERNET,
                Manifest.permission.ACCESS_NETWORK_STATE
        };
    }

    public static boolean hasPermission(Context context, String permission) {
        return ContextCompat.checkSelfPermission(context, permission) ==
                android.content.pm.PackageManager.PERMISSION_GRANTED;
    }

    public static boolean hasAllPermissions(Context context, String[] permissions) {
        for (String perm : permissions) {
            if (!hasPermission(context, perm)) return false;
        }
        return true;
    }
}

package com.hfad.agencyapp.utils;

import android.text.TextUtils;

import java.util.regex.Pattern;

public class ValidationUtils {

    private static final String EMAIL_PATTERN = "[a-zA-Z0-9._-]+@[a-z]+\\.+[a-z]+";
    private static final Pattern EMAIL_REGEX = Pattern.compile(EMAIL_PATTERN);

    public static boolean isValidEmail(String email) {
        return !TextUtils.isEmpty(email) && EMAIL_REGEX.matcher(email).matches();
    }

    public static boolean isValidPhone(String phone) {
        return !TextUtils.isEmpty(phone) && phone.length() >= 10;
    }

    public static boolean isValidPassword(String password) {
        return !TextUtils.isEmpty(password) && password.length() >= 6;
    }

    public static boolean isValidName(String name) {
        return !TextUtils.isEmpty(name) && name.length() >= 2;
    }

    public static boolean isValidAmount(double amount) {
        return amount > 0;
    }

    public static boolean isValidQuantity(int quantity) {
        return quantity > 0;
    }

    public static boolean isNotEmpty(String text) {
        return !TextUtils.isEmpty(text);
    }

    public static String getErrorMessage(String fieldName, String errorType) {
        switch (errorType) {
            case "empty":
                return fieldName + " is required";
            case "invalid_email":
                return "Invalid email format";
            case "invalid_phone":
                return "Phone number must be at least 10 digits";
            case "invalid_password":
                return "Password must be at least 6 characters";
            case "invalid_name":
                return fieldName + " must be at least 2 characters";
            case "invalid_amount":
                return "Amount must be greater than 0";
            default:
                return "Invalid " + fieldName;
        }
    }
}

package com.hfad.agencyapp.viewmodel;

import android.app.Application;
import android.util.Log;

import androidx.annotation.NonNull;
import androidx.lifecycle.AndroidViewModel;
import androidx.lifecycle.MutableLiveData;

import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;

public class AuthViewModel extends AndroidViewModel {

    private static final String TAG = "AuthViewModel";
    private FirebaseAuth firebaseAuth;
    public final MutableLiveData<FirebaseUser> userLive = new MutableLiveData<>();
    public final MutableLiveData<Boolean> loading = new MutableLiveData<>(false);
    public final MutableLiveData<String> errorMessage = new MutableLiveData<>();

    public AuthViewModel(@NonNull Application application) {
        super(application);
        try {
            firebaseAuth = FirebaseAuth.getInstance();
            if (firebaseAuth != null) {
                userLive.setValue(firebaseAuth.getCurrentUser());
            }
        } catch (Exception e) {
            Log.w(TAG, "Firebase not initialized. Make sure google-services.json is configured.", e);
            errorMessage.setValue("Firebase not configured. Please add google-services.json to app/ directory.");
            firebaseAuth = null;
        }
    }

    public void signIn(String email, String password) {
        if (firebaseAuth == null) {
            errorMessage.postValue("Firebase not initialized. Please add google-services.json to app/ directory.");
            return;
        }

        if (email == null || email.isEmpty() || password == null || password.isEmpty()) {
            errorMessage.postValue("Email and password are required");
            return;
        }

        loading.postValue(true);
        firebaseAuth.signInWithEmailAndPassword(email, password)
                .addOnCompleteListener(task -> {
                    loading.postValue(false);
                    if (task.isSuccessful()) {
                        userLive.postValue(firebaseAuth.getCurrentUser());
                        errorMessage.postValue(null);
                    } else {
                        errorMessage.postValue(task.getException() != null ? task.getException().getMessage() : "Sign in failed");
                        userLive.postValue(null);
                    }
                });
    }

    public void signUp(String email, String password) {
        if (firebaseAuth == null) {
            errorMessage.postValue("Firebase not initialized. Please add google-services.json to app/ directory.");
            return;
        }

        if (email == null || email.isEmpty() || password == null || password.isEmpty()) {
            errorMessage.postValue("Email and password are required");
            return;
        }

        loading.postValue(true);
        firebaseAuth.createUserWithEmailAndPassword(email, password)
                .addOnCompleteListener(task -> {
                    loading.postValue(false);
                    if (task.isSuccessful()) {
                        userLive.postValue(firebaseAuth.getCurrentUser());
                        errorMessage.postValue(null);
                    } else {
                        errorMessage.postValue(task.getException() != null ? task.getException().getMessage() : "Sign up failed");
                        userLive.postValue(null);
                    }
                });
    }

    public void signOut() {
        if (firebaseAuth != null) {
            firebaseAuth.signOut();
        }
        userLive.postValue(null);
    }

    public FirebaseUser getCurrentUser() {
        return firebaseAuth != null ? firebaseAuth.getCurrentUser() : null;
    }
}

package com.hfad.agencyapp.viewmodel;

import android.app.Application;

import androidx.annotation.NonNull;
import androidx.lifecycle.AndroidViewModel;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;

import com.hfad.agencyapp.data.Repository;
import com.hfad.agencyapp.data.entities.Category;
import com.hfad.agencyapp.data.entities.Product;
import com.hfad.agencyapp.data.entities.Invoice;
import com.hfad.agencyapp.data.entities.Customer;

import java.util.List;

public class DashboardViewModel extends AndroidViewModel {

    private final Repository repository;
    public final LiveData<List<Product>> products;
    public final LiveData<List<Category>> categories;
    public final LiveData<List<Invoice>> invoices;
    public final LiveData<List<Customer>> customers;
    public final MutableLiveData<Integer> loadingCount = new MutableLiveData<>(0);

    public DashboardViewModel(@NonNull Application application) {
        super(application);
        repository = Repository.getInstance(application);
        products = repository.getAllProducts();
        categories = repository.getAllCategories();
        invoices = repository.getAllInvoices();
        customers = repository.getAllCustomers();
        loadData();
    }

    public void loadData() {
        // Data auto-loads via LiveData from Repository
    }

    public void insertProduct(String name, String sku, long categoryId, double price, int stock, String imageUrl) {
        Product product = new Product(name, sku, categoryId, price, stock, imageUrl);
        repository.insertProduct(product);
    }

    public void insertCustomer(String name, String phone, String email, String address) {
        Customer customer = new Customer(name, phone, email, address);
        repository.insertCustomer(customer);
    }

    public void insertInvoice(long customerId, String invoiceNumber, double totalAmount, String note) {
        Invoice invoice = new Invoice(customerId, invoiceNumber, System.currentTimeMillis(), totalAmount, 0, note, "PENDING");
        repository.insertInvoice(invoice);
    }

    @Override
    protected void onCleared() {
        super.onCleared();
        repository.shutdown();
    }
}

package com.hfad.agencyapp.viewmodel;

import android.app.Application;

import androidx.annotation.NonNull;
import androidx.lifecycle.AndroidViewModel;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;

import com.hfad.agencyapp.data.Repository;
import com.hfad.agencyapp.data.entities.Invoice;
import com.hfad.agencyapp.data.entities.InvoiceItem;
import com.hfad.agencyapp.data.entities.Payment;

import java.util.List;

public class InvoiceViewModel extends AndroidViewModel {

    private final Repository repository;
    public final MutableLiveData<Long> currentInvoiceId = new MutableLiveData<>();
    public final LiveData<Invoice> currentInvoice;
    public final LiveData<List<InvoiceItem>> invoiceItems;
    public final LiveData<List<Payment>> payments;

    public InvoiceViewModel(@NonNull Application application) {
        super(application);
        repository = Repository.getInstance(application);
        currentInvoice = new MutableLiveData<>();
        invoiceItems = new MutableLiveData<>();
        payments = new MutableLiveData<>();

        currentInvoiceId.observeForever(id -> {
            if (id != null && id > 0) {
                loadInvoice(id);
            }
        });
    }

    public void setCurrentInvoice(long invoiceId) {
        currentInvoiceId.setValue(invoiceId);
    }

    private void loadInvoice(long invoiceId) {
        ((MutableLiveData<Invoice>) currentInvoice).setValue(null);
        repository.getInvoiceById(invoiceId).observeForever(invoice -> {
            if (invoice != null) {
                ((MutableLiveData<Invoice>) currentInvoice).setValue(invoice);
            }
        });

        ((MutableLiveData<List<InvoiceItem>>) invoiceItems).setValue(null);
        repository.getInvoiceItems(invoiceId).observeForever(items -> {
            if (items != null) {
                ((MutableLiveData<List<InvoiceItem>>) invoiceItems).setValue(items);
            }
        });

        ((MutableLiveData<List<Payment>>) payments).setValue(null);
        repository.getPaymentsByInvoice(invoiceId).observeForever(paymentList -> {
            if (paymentList != null) {
                ((MutableLiveData<List<Payment>>) payments).setValue(paymentList);
            }
        });
    }

    public void addInvoiceItem(long invoiceId, long productId, int quantity, double unitPrice, double totalPrice) {
        InvoiceItem item = new InvoiceItem(invoiceId, productId, quantity, unitPrice, totalPrice);
        repository.insertInvoiceItem(item);
    }

    public void addPayment(long invoiceId, double amount, String method) {
        Payment payment = new Payment(invoiceId, amount, System.currentTimeMillis(), method);
        repository.insertPayment(payment);
    }

    @Override
    protected void onCleared() {
        super.onCleared();
        repository.shutdown();
    }
}

